const msg = $input.first().json.message || {};
const chatId = msg.chat?.id ? String(msg.chat.id) : '';
const rawText = String(msg.text || msg.caption || '').trim();

function sqlQuote(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlInt(value) {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) ? String(parsed) : 'NULL';
}

function cleanQuery(text) {
  return text
    .replace(/^\/search(?:@\w+)?\s*/i, '')
    .replace(/^пошук\s*:?\s*/i, '')
    .trim();
}

const helpSql = `SELECT
  'help'::text AS response_type,
  ${sqlQuote(chatId)}::text AS chat_id,
  NULL::text AS query,
  NULL::integer AS result_number,
  0::integer AS result_count,
  '[]'::jsonb AS results,
  NULL::jsonb AS recipe;`;

let route = 'help';
let query = cleanQuery(rawText);
let resultNumber = null;
let recipeId = null;
let searchSql = helpSql;

const listNumberMatch = rawText.match(/^#?(\d{1,2})$/);
const recipeIdMatch = rawText.match(/^\/recipe(?:@\w+)?\s+(\d+)$/i);
const isHelp = !rawText || /^\/(start|help)(?:@\w+)?$/i.test(rawText) || /^допомога$/i.test(rawText);

if (!chatId) {
  route = 'error';
  searchSql = `SELECT 'error'::text AS response_type, ''::text AS chat_id, NULL::text AS query, NULL::integer AS result_number, 0::integer AS result_count, '[]'::jsonb AS results, jsonb_build_object('message', 'Не вдалося визначити chat_id.') AS recipe;`;
} else if (isHelp) {
  route = 'help';
  searchSql = helpSql;
} else if (recipeIdMatch) {
  route = 'recipe_id';
  recipeId = Number.parseInt(recipeIdMatch[1], 10);
  searchSql = `WITH selected AS (
  SELECT id, title, category, description, youtube_url, youtube_channel, nextcloud_docx_url, nextcloud_pdf_url, updated_at
  FROM recipes
  WHERE id = ${sqlInt(recipeId)}
  LIMIT 1
)
SELECT
  'recipe_id'::text AS response_type,
  ${sqlQuote(chatId)}::text AS chat_id,
  NULL::text AS query,
  NULL::integer AS result_number,
  COUNT(selected.id)::integer AS result_count,
  '[]'::jsonb AS results,
  CASE WHEN COUNT(selected.id) = 0 THEN NULL ELSE jsonb_build_object(
    'id', MAX(selected.id),
    'title', MAX(selected.title),
    'category', MAX(selected.category),
    'description', MAX(selected.description),
    'youtube_url', MAX(selected.youtube_url),
    'youtube_channel', MAX(selected.youtube_channel),
    'docx_url', MAX(selected.nextcloud_docx_url),
    'pdf_url', MAX(selected.nextcloud_pdf_url),
    'updated_at', MAX(selected.updated_at)::text
  ) END AS recipe
FROM selected;`;
} else if (listNumberMatch) {
  route = 'select';
  resultNumber = Number.parseInt(listNumberMatch[1], 10);
  searchSql = `WITH selected_session AS (
  SELECT recipe_id, query, result_number, created_at
  FROM telegram_search_sessions
  WHERE chat_id = ${sqlQuote(chatId)}
    AND result_number = ${sqlInt(resultNumber)}
    AND created_at > NOW() - INTERVAL '6 hours'
  ORDER BY created_at DESC
  LIMIT 1
), selected AS (
  SELECT r.id, r.title, r.category, r.description, r.youtube_url, r.youtube_channel,
         r.nextcloud_docx_url, r.nextcloud_pdf_url, r.updated_at,
         s.query, s.result_number
  FROM selected_session s
  JOIN recipes r ON r.id = s.recipe_id
)
SELECT
  'select'::text AS response_type,
  ${sqlQuote(chatId)}::text AS chat_id,
  MAX(selected.query)::text AS query,
  ${sqlInt(resultNumber)}::integer AS result_number,
  COUNT(selected.id)::integer AS result_count,
  '[]'::jsonb AS results,
  CASE WHEN COUNT(selected.id) = 0 THEN NULL ELSE jsonb_build_object(
    'id', MAX(selected.id),
    'number', MAX(selected.result_number),
    'title', MAX(selected.title),
    'category', MAX(selected.category),
    'description', MAX(selected.description),
    'youtube_url', MAX(selected.youtube_url),
    'youtube_channel', MAX(selected.youtube_channel),
    'docx_url', MAX(selected.nextcloud_docx_url),
    'pdf_url', MAX(selected.nextcloud_pdf_url),
    'updated_at', MAX(selected.updated_at)::text
  ) END AS recipe
FROM selected;`;
} else if (query.length >= 2) {
  route = 'search';
  const querySql = sqlQuote(query.toLowerCase());
  const patternSql = sqlQuote(`%${query.toLowerCase()}%`);
  searchSql = `WITH input AS (
  SELECT ${sqlQuote(chatId)}::text AS chat_id,
         ${querySql}::text AS query,
         ${patternSql}::text AS pattern
), ranked AS (
  SELECT
    r.id,
    r.title,
    r.category,
    r.youtube_url,
    r.youtube_channel,
    r.nextcloud_docx_url,
    r.nextcloud_pdf_url,
    r.updated_at,
    GREATEST(
      similarity(lower(r.title), input.query),
      similarity(lower(COALESCE(r.category, '')), input.query),
      similarity(lower(COALESCE(r.description, '')), input.query),
      similarity(lower(COALESCE(r.ingredients::text, '')), input.query)
    ) AS similarity_score,
    (CASE WHEN lower(r.title) LIKE input.pattern THEN 8 ELSE 0 END) +
    (CASE WHEN lower(COALESCE(r.category, '')) LIKE input.pattern THEN 4 ELSE 0 END) +
    (CASE WHEN lower(COALESCE(r.ingredients::text, '')) LIKE input.pattern THEN 3 ELSE 0 END) +
    (CASE WHEN lower(COALESCE(r.description, '')) LIKE input.pattern THEN 1 ELSE 0 END) AS hit_score
  FROM recipes r
  CROSS JOIN input
  WHERE r.processed = TRUE
    AND (r.nextcloud_pdf_url IS NOT NULL OR r.nextcloud_docx_url IS NOT NULL)
    AND (
      lower(r.title) LIKE input.pattern
      OR lower(COALESCE(r.category, '')) LIKE input.pattern
      OR lower(COALESCE(r.description, '')) LIKE input.pattern
      OR lower(COALESCE(r.ingredients::text, '')) LIKE input.pattern
      OR similarity(lower(r.title), input.query) > 0.18
      OR similarity(lower(COALESCE(r.description, '')), input.query) > 0.18
    )
), numbered AS (
  SELECT ROW_NUMBER() OVER (ORDER BY hit_score DESC, similarity_score DESC, updated_at DESC, id DESC)::integer AS result_number,
         id, title, category, youtube_url, youtube_channel, nextcloud_docx_url, nextcloud_pdf_url, updated_at,
         similarity_score, hit_score
  FROM ranked
  ORDER BY hit_score DESC, similarity_score DESC, updated_at DESC, id DESC
  LIMIT 10
), cleared AS (
  DELETE FROM telegram_search_sessions
  WHERE chat_id = (SELECT chat_id FROM input)
     OR created_at < NOW() - INTERVAL '6 hours'
), inserted AS (
  INSERT INTO telegram_search_sessions (chat_id, result_number, recipe_id, query, created_at)
  SELECT (SELECT chat_id FROM input), result_number, id, (SELECT query FROM input), NOW()
  FROM numbered
  RETURNING recipe_id
)
SELECT
  'search'::text AS response_type,
  input.chat_id,
  input.query,
  NULL::integer AS result_number,
  COUNT(numbered.id)::integer AS result_count,
  COALESCE(jsonb_agg(jsonb_build_object(
    'number', numbered.result_number,
    'id', numbered.id,
    'title', numbered.title,
    'category', numbered.category,
    'youtube_channel', numbered.youtube_channel,
    'youtube_url', numbered.youtube_url,
    'docx_url', numbered.nextcloud_docx_url,
    'pdf_url', numbered.nextcloud_pdf_url
  ) ORDER BY numbered.result_number) FILTER (WHERE numbered.id IS NOT NULL), '[]'::jsonb) AS results,
  NULL::jsonb AS recipe
FROM input
LEFT JOIN numbered ON TRUE
GROUP BY input.chat_id, input.query;`;
} else {
  route = 'help';
  searchSql = helpSql;
}

return [{
  json: {
    chat_id: chatId,
    text: rawText,
    query,
    route,
    result_number: resultNumber,
    recipe_id: recipeId,
    search_sql: searchSql
  }
}];

const row = $input.first().json || {};

function parseJson(value, fallback) {
  if (value === null || value === undefined) return fallback;
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (error) {
      return fallback;
    }
  }
  return value;
}

function compact(value, fallback = 'не вказано') {
  const text = String(value || '').trim();
  return text || fallback;
}

function lineUrl(label, url) {
  const clean = String(url || '').trim();
  return clean ? `${label}: ${clean}` : '';
}

function shortDescription(value) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (!text) return '';
  return text.length > 260 ? `${text.slice(0, 257)}...` : text;
}

const responseType = row.response_type || 'help';
const chatId = String(row.chat_id || '');
const results = parseJson(row.results, []);
const recipe = parseJson(row.recipe, null);
let message = '';

if (responseType === 'search') {
  const query = compact(row.query, '');
  if (!Array.isArray(results) || results.length === 0) {
    message = `За запитом "${query}" нічого не знайшла.\n\nСпробуй інші слова: наприклад, "курка", "млинці", "десерт", "салат".`;
  } else {
    const lines = results.map((item) => {
      const header = `${item.number}. ${compact(item.title)} (${compact(item.category, 'Інше')})`;
      const links = [lineUrl('PDF', item.pdf_url), lineUrl('DOCX', item.docx_url)].filter(Boolean).join('\n');
      return `${header}\n${links}`;
    });
    message = `Знайшла ${results.length} рецепт(ів) за запитом "${query}".\n\n${lines.join('\n\n')}\n\nНапиши номер зі списку, наприклад: 1. Також можна відкрити пряме посилання PDF/DOCX.`;
  }
} else if (responseType === 'select' || responseType === 'recipe_id') {
  if (!recipe) {
    message = responseType === 'select'
      ? 'Не знайшла рецепт за цим номером. Список міг застаріти, зроби пошук ще раз.'
      : 'Не знайшла рецепт з таким ID.';
  } else {
    const parts = [
      `${compact(recipe.title)}`,
      `Категорія: ${compact(recipe.category, 'Інше')}`,
      `Канал: ${compact(recipe.youtube_channel)}`,
      shortDescription(recipe.description),
      lineUrl('PDF', recipe.pdf_url),
      lineUrl('DOCX', recipe.docx_url),
      lineUrl('YouTube', recipe.youtube_url),
      `ID рецепта: ${recipe.id}`
    ].filter(Boolean);
    message = parts.join('\n\n');
  }
} else if (responseType === 'error') {
  message = recipe?.message || 'Сталася помилка під час обробки повідомлення.';
} else {
  message = 'Пошук рецептів готовий.\n\nНапиши, що шукаємо, наприклад:\nкурка з млинцями\nдесерт\nпечериці\n\nПісля списку результатів напиши номер, наприклад: 1.\nТакож можна відкрити рецепт напряму командою /recipe 35.';
}

return [{ json: { chat_id: chatId, text: message } }];
